#usda 1.0
(
    defaultPrim = "CameraRig"
)

def Xform "CameraRig"
{
    def Camera "MainCamera"
    {
        float2 clippingRange = (0.1, 10000)
        float focalLength = 50
        float horizontalAperture = 36
        float3 xformOp:rotateXYZ = (-15, 0, 0)
        double3 xformOp:translate = (0, 5, 20)
        uniform token[] xformOpOrder = ["xformOp:translate", "xformOp:rotateXYZ"]
    }
}

#usda 1.0
(
    defaultPrim = "Render"
    subLayers = [
        @./camera_rig.usda@
    ]
)

def Xform "Render"
{
    def RenderProduct "RenderProduct"
    {
        token productName = "beauty.exr"

        def RenderVar "beauty"
        {
            uniform token dataType = "color3f"
            uniform string sourceName = "Ci"
        }

        def RenderVar "depth"
        {
            uniform token dataType = "float"
            uniform string sourceName = "z"
        }

        def RenderVar "normal"
        {
            uniform token dataType = "normal3f"
            uniform string sourceName = "N"
        }
    }

    def RenderSettings "RenderSettings"
    {
        rel camera = </CameraRig/MainCamera>
        uniform float pixelAspectRatio = 1
        uniform int2 resolution = (1920, 1080)
    }
}
